            SystemDefaultsDiagnosis::Unavailable { requested, reason } => serde_json::json!({
                "available": false,
                "reason": reason,
                "requested": requested,
            }),
            SystemDefaultsDiagnosis::Checked {
                requested,
                out_of_sync,
            } => serde_json::json!({
                "available": true,
                "requested": requested,
                "out_of_sync": out_of_sync,
            }),
            SystemDefaultsDiagnosis::CheckFailed { requested, error } => serde_json::json!({
                "available": true,
                "requested": requested,
                "error": error,
            }),
        };
        Some(json)
    }

